import {
  StringField,
  NumberField,
} from "../../../decorators/field.decorators.ts";

export class AccountInquiryResponseDto {
  @StringField()
  request_id!: string;

  @StringField()
  account_number!: string;

  @NumberField({ int: true })
  status_code!: number;

  @StringField()
  status_desc!: string;

  @NumberField({ int: false })
  amount!: number;

  @StringField()
  cid_no!: string;

  @StringField()
  full_name!: string;
}
